namespace sv_afa57f5fda734880b872fc499b0cf99e.Services;

public sealed class Recipe
{
    public int Id { get; init; }
    public string Title { get; init; } = string.Empty;
    public string Description { get; init; } = string.Empty;
    public int PrepTimeMinutes { get; init; }
}

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _seedData = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic Italian pizza with tomato, mozzarella, and basil.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Pasta Carbonara", Description = "Creamy Roman pasta with eggs, pecorino, and guanciale.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered coffee-flavored dessert with mascarpone cream.", PrepTimeMinutes = 45 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Pad Thai", Description = "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", PrepTimeMinutes = 20 },
            new() { Id = 5, Title = "Green Curry", Description = "Aromatic coconut curry with vegetables and Thai basil.", PrepTimeMinutes = 35 },
            new() { Id = 6, Title = "Tom Yum Soup", Description = "Hot and sour soup with lemongrass, galangal, and prawns.", PrepTimeMinutes = 25 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Marinated pork tacos with pineapple, onion, and cilantro.", PrepTimeMinutes = 40 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, cilantro, and jalapeño.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Churros", Description = "Fried dough pastry dusted with cinnamon sugar.", PrepTimeMinutes = 30 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (_seedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_afa57f5fda734880b872fc499b0cf99e.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override Task OnParametersSetAsync()
    {
        // Only reload if the cuisine actually changed
        if (CuisineId != _loadedCuisineId || (_recipes is null && _error is null))
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);
            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

